  <svg viewBox="0 0 700 400" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
    <text x="20" y="32" fill="#fafafa" font-size="17" font-weight="700" font-family="sans-serif">FTSE移行までのタイムライン</text>
    <text x="20" y="56" fill="#a1a1aa" font-size="13" font-family="sans-serif">21Shareソラナ・イーサリアム・XRP ETFベンチマーク移行の主要日程</text>
    <line x1="60" y1="200" x2="650" y2="200" stroke="#3f3f46" stroke-width="2"/>
    <circle cx="110" cy="200" r="7" fill="#0ea5e9"/>
    <circle cx="290" cy="200" r="7" fill="#f59e0b"/>
